/**
 * Editor extensions for pack-core (TRN-109, TRN-146).
 *
 * Registers custom inspectors:
 *  - `inspectors['LODGroup']` → LODGroupInspector (Unity-style LOD bar widget).
 *  - `inspectors['BatchingController']` → BatchingControllerInspector
 *    (bulk Mark/Unmark Static accordion, ADR-0015 §2, TRN-146).
 *
 * The inspectors replace the generic field loop for their respective component
 * types only; all other pack-core components (MeshRenderer, Camera, etc.)
 * continue to use the generic schema-driven inspector.
 *
 * Tree-shaking: this file is the `./editor` export of pack-core. The runtime
 * entry point (`src/index.ts`) does NOT re-export it, so no widget JSX or
 * React import reaches the game bundle.
 *
 * Import only from editor-app or editor bootstrap code — not from runtime.
 */

import type { PackEditorExtensions } from '@threenity/components-sdk';
import { LODGroupInspector } from './widgets/LODGroupInspector.js';
import { BatchingControllerInspector } from './widgets/BatchingControllerInspector.js';

export { isEligibleForStaticMark, checkStaticEligibility } from '../batching/eligibilityCheck.js';
export type { StaticEligibilityResult, StaticBlockReason } from '../batching/eligibilityCheck.js';

// TRN-343: "Why isn't this batched?" inspector — editor-only diagnostic API.
export { findSimilarMeshes, parseBatchKey } from '../batching/whyNotBatched.js';
export type {
  SimilarMeshResult,
  BatchKeyBreakdown,
  BatchGroupInspectResult,
} from '../batching/whyNotBatched.js';
export { BatchGroupInspector } from './widgets/BatchGroupInspector.js';
export type { BatchGroupInspectorProps } from './widgets/BatchGroupInspector.js';
export { mountProfilerBatchOverlay } from './widgets/ProfilerBatchOverlay.js';
export type { ProfilerBatchOverlayHandle } from './widgets/ProfilerBatchOverlay.js';
export { mountSceneReportWidget } from './widgets/SceneReportWidget.js';
export type { SceneReportWidgetHandle } from './widgets/SceneReportWidget.js';

// TRN-348: scene report — heuristics + report builder (editor-only).
export {
  runHeuristics,
  hintAtlasCandidates,
  hintPerInstanceVariant,
  hintShaderProgramCount,
  hintSplitMapGroups,
} from './sceneReport/heuristics.js';
export type { MaterialDescriptor, BatchGroupDescriptor, SceneReportInput } from './sceneReport/heuristics.js';
export { buildSceneReport } from './sceneReport/buildSceneReport.js';
export type { SceneReportOptions } from './sceneReport/buildSceneReport.js';

const PACK_CORE_INSPECTOR_MAP: Record<string, unknown> = {
  LODGroup: LODGroupInspector,
  BatchingController: BatchingControllerInspector,
};

export const packCoreEditorExtensions: PackEditorExtensions = {
  inspectors: PACK_CORE_INSPECTOR_MAP,
};
