/**
 * BatchGroupInspector — "Why isn't this batched?" side panel (TRN-343).
 *
 * Editor-only. Rendered when a user clicks a batch group row in the Profiler
 * HUD or the BatchingController inspector. Shows:
 *  1. The batch key broken down into named fields (hover shows value).
 *  2. A mesh list (name + uuid) for all objects in the selected batch group.
 *  3. A "Find similar" list: same-primitive objects that are rejected from the
 *     group, each with a one-line reason derived from criteria.ts / keygen.ts.
 *  4. Click-to-select wiring via the `onSelectObject` callback.
 *
 * The panel is a snapshot: it reads state on open. Users re-open to refresh.
 * This satisfies the "live-update during play mode" out-of-scope constraint.
 *
 * No import from @threenity/editor-ui — respects pack ↔ editor-ui boundary.
 * The caller (editor-app or editor-ui panel host) passes callbacks for scene
 * access and selection so this component stays agnostic to the store.
 */

import { useState, useMemo } from 'react';
import type { BatchGroupInspectResult, SimilarMeshResult } from '../../batching/whyNotBatched.js';
import { parseBatchKey } from '../../batching/whyNotBatched.js';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface BatchGroupInspectorProps {
  /**
   * The batch key string of the group being inspected (e.g. from BatchingStats.byKey).
   * When null the panel renders an empty/closed state.
   */
  batchKey: string | null;

  /**
   * Pre-computed result of findSimilarMeshes for the current batchKey.
   * The caller is responsible for running findSimilarMeshes (so it can inject
   * the live scene + registry without BatchGroupInspector importing THREE).
   * Null when no scan has been run yet (e.g. key just changed).
   */
  inspectResult: BatchGroupInspectResult | null;

  /**
   * Names + uuids of all mesh objects currently in this batch group.
   * Used for the "Meshes in this group" list.
   */
  groupMembers: Array<{ uuid: string; name: string }>;

  /**
   * Called when the user clicks a mesh row to select it in the editor.
   * Passes the Object3D uuid. May be undefined in environments without a
   * selection API (e.g. unit tests rendering the panel in isolation).
   */
  onSelectObject?: (uuid: string) => void;

  /**
   * Called when the user clicks "Find similar" to trigger a scene scan.
   * The caller runs findSimilarMeshes and updates `inspectResult`.
   */
  onFindSimilar?: () => void;

  /**
   * Called when the user closes the panel (X button or clicks away).
   */
  onClose?: () => void;
}

