// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

function KeyBreakdownSection({ batchKey }: { batchKey: string }): JSX.Element {
  const breakdown = useMemo(() => parseBatchKey(batchKey), [batchKey]);

  const fields: Array<[string, string]> = [
    ['Primitive', breakdown.primitive],
    ['Material', breakdown.materialId],
    ['Cast Shadow', breakdown.castShadow ? 'yes' : 'no'],
    ['Receive Shadow', breakdown.receiveShadow ? 'yes' : 'no'],
    ['Layer mask', String(breakdown.layerMask)],
    ['Frustum Culled', breakdown.frustumCulled ? 'yes' : 'no'],
  ];
  if (breakdown.uvScale) {
    fields.push(['UV scale (world)', breakdown.uvScale]);
  }

  return (
    <>
      <div style={sectionHeaderStyle}>Batch key</div>
      {fields.map(([label, value]) => (
        <div key={label} style={keyFieldRowStyle} title={`${label}: ${value}`}>
          <span style={keyFieldLabelStyle}>{label}</span>
          <span style={keyFieldValueStyle}>{value}</span>
        </div>
      ))}
      <div style={{ ...keyFieldRowStyle, flexDirection: 'column', gap: 0 }}>
        <span style={{ ...keyFieldLabelStyle, width: 'auto', marginBottom: 2 }}>Raw key</span>
        <span style={{ ...keyFieldValueStyle, fontSize: 9, color: 'var(--sf-text-dim)' }}>
          {breakdown.raw}
        </span>
      </div>
    </>
  );
}

function MeshRow({
  uuid,
  name,
  onSelect,
}: {
  uuid: string;
  name: string;
  onSelect?: (uuid: string) => void;
}): JSX.Element {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      style={hovered ? rowHoverStyle : rowStyle}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={() => onSelect?.(uuid)}
      title={uuid}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onSelect?.(uuid); }}
    >
      <span style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
        {name || '<unnamed>'}
      </span>
      <span style={{ color: 'var(--sf-text-dim)', fontFamily: 'ui-monospace, Menlo, Consolas, monospace', fontSize: 9 }}>
        {uuid.slice(0, 8)}
      </span>
    </div>
  );
}

function RejectedMeshRow({
  result,
  onSelect,
}: {
  result: SimilarMeshResult;
  onSelect?: (uuid: string) => void;
}): JSX.Element {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      style={hovered ? rowHoverStyle : rowStyle}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={() => onSelect?.(result.uuid)}
      title={`${result.name || '<unnamed>'} — ${result.reason}`}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onSelect?.(result.uuid); }}
    >
      <span style={{ minWidth: 80, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
        {result.name || '<unnamed>'}
      </span>
      <span style={reasonStyle}>{result.reason}</span>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Main panel
// ---------------------------------------------------------------------------

export function BatchGroupInspector({
  batchKey,
  inspectResult,
  groupMembers,
  onSelectObject,
  onFindSimilar,
  onClose,
}: BatchGroupInspectorProps): JSX.Element | null {
  if (!batchKey) return null;

  return (
    <div style={panelStyle} data-testid="batch-group-inspector">
      <div style={headerStyle}>
        <span style={headerTitleStyle}>Batch group inspector</span>
        {onClose ? (
          <button type="button" style={closeButtonStyle} onClick={onClose} aria-label="Close">
            ✕
          </button>
        ) : null}
      </div>

      <div style={scrollBodyStyle}>
        <KeyBreakdownSection batchKey={batchKey} />

        <div style={sectionHeaderStyle}>
          Meshes in this group ({groupMembers.length})
        </div>
        {groupMembers.length === 0 ? (
          <div style={emptyStyle}>No mesh data available (panel opened before batch ran).</div>
        ) : (
          groupMembers.map((m) => (
            <MeshRow key={m.uuid} uuid={m.uuid} name={m.name} onSelect={onSelectObject} />
          ))
        )}

        <div style={sectionHeaderStyle}>Find similar (same geometry, different batch)</div>
        <button type="button" style={findButtonStyle} onClick={onFindSimilar}>
          Find similar meshes
        </button>

        {inspectResult === null ? (
          <div style={emptyStyle}>Click "Find similar meshes" to scan the scene.</div>
        ) : inspectResult.similarRejected.length === 0 ? (
          <div style={emptyStyle}>No rejected candidates found — all similar meshes are in this batch.</div>
        ) : (
          inspectResult.similarRejected.map((r) => (
            <RejectedMeshRow key={r.uuid} result={r} onSelect={onSelectObject} />
          ))
        )}
      </div>
    </div>
  );
}
