/**
 * whyNotBatched — "Find similar" diagnostic for the Profiler batch inspector.
 *
 * Editor-only module. Not re-exported from pack-core's runtime index.ts.
 * Import exclusively from editor code (pack-core/src/editor/* or editor-app).
 *
 * Given a target Object3D that IS batchable (already in a batch group), this
 * module scans the scene for other objects that share the same geometry but
 * end up in a different batch group, and reports the first rejection reason
 * per object.
 *
 * Reason strings come directly from criteria.ts ExclusionReason and keygen.ts
 * field names — no hand-maintained copy. When criteria.ts gains a new
 * ExclusionReason, it surfaces here automatically.
 */

import * as THREE from 'three';
import type { ComponentRegistryImpl } from '@threenity/components-sdk';
import { isBatchable, type ExclusionReason } from './criteria.js';
import { getBatchKey } from './keygen.js';

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/**
 * A candidate mesh found by "Find similar" that shares geometry with the target
 * but is rejected from the same batch, plus the first human-readable reason.
 */
export interface SimilarMeshResult {
  /** Three.js Object3D uuid of the candidate host object. */
  uuid: string;
  /** Display name of the host object (Object3D.name, may be empty string). */
  name: string;
  /**
   * First rejection reason, in one of two forms:
   *  - An ExclusionReason string from criteria.ts (e.g. "noBatch", "not-static")
   *    when the object failed the batchability check.
   *  - A "key:<field>:<value-a>-vs-<value-b>" string when the object is batchable
   *    but its batch key differs from the target's key.
   */
  reason: string;
}

/**
 * Parsed breakdown of a batch key produced by getBatchKey.
 * Used by the panel to render individual fields with hover-values.
 */
export interface BatchKeyBreakdown {
  /** e.g. "Cube", "Sphere" */
  primitive: string;
  /** material asset id or "__placeholder" */
  materialId: string;
  castShadow: boolean;
  receiveShadow: boolean;
  /** THREE.Layers.mask value */
  layerMask: number;
  frustumCulled: boolean;
  /** Present for worldSpaceUV materials — e.g. "1.0000,1.0000" */
  uvScale?: string;
  /** Raw key string for display / copy. */
  raw: string;
}

/**
 * Full result of a "Find similar" scan for a specific batch group key.
 */
export interface BatchGroupInspectResult {
  /** The batch key for the reference group. */
  referenceKey: string;
  /** Parsed batch-key fields for display. */
  keyBreakdown: BatchKeyBreakdown;
  /** Objects that have the same geometry but land in a different batch key or are excluded. */
  similarRejected: SimilarMeshResult[];
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Extract the MeshRenderer duck-type from an Object3D's sfComponents array.
 * Returns null if none found.
 */
function getMeshRenderer(obj: THREE.Object3D): {
  noBatch: boolean;
  primitive: string;
  material?: string | null;
  castShadow: boolean;
  receiveShadow: boolean;
  frustumCulled: boolean;
} | null {
  const sfComponents = obj.userData['sfComponents'];
  if (!Array.isArray(sfComponents)) return null;
  for (const c of sfComponents as unknown[]) {
    if (
      c !== null &&
      typeof c === 'object' &&
      typeof (c as Record<string, unknown>)['primitive'] === 'string' &&
      typeof (c as Record<string, unknown>)['noBatch'] === 'boolean'
    ) {
      return c as {
        noBatch: boolean;
        primitive: string;
        material?: string | null;
        castShadow: boolean;
        receiveShadow: boolean;
        frustumCulled: boolean;
      };
    }
  }
  return null;
}

/** Get the first non-instanced child Mesh of a host Object3D. */
function getHostMesh(obj: THREE.Object3D): THREE.Mesh | null {
  for (const child of obj.children) {
    if (child instanceof THREE.Mesh && !(child instanceof THREE.InstancedMesh)) {
      return child;
    }
  }
  return null;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Parse a raw batch key string into its named fields.
 * Format from keygen.ts:
 *   `${primitive}|${materialId}|${castShadow}|${receiveShadow}|${layerMask}|${frustumCulled}[|${uvX},${uvY}]`
 */
export function parseBatchKey(raw: string): BatchKeyBreakdown {
  const parts = raw.split('|');
  return {
    primitive: parts[0] ?? '',
    materialId: parts[1] ?? '__placeholder',
    castShadow: parts[2] === '1',
    receiveShadow: parts[3] === '1',
    layerMask: Number(parts[4] ?? 1),
    frustumCulled: parts[5] === '1',
    uvScale: parts[6],
    raw,
  };
}

/**
 * Scan `scene` for mesh objects that share the same primitive as the target's
 * batch key but are rejected from that batch, returning one reason per object.
 *
 * "Same geometry" is approximated by matching the `primitive` field of the
 * batch key — this is the MeshRenderer.primitive string (e.g. "Cube", "Sphere").
 * Custom-geometry objects all share primitive "Custom" so they also cluster.
 *
 * The target object itself is excluded from results.
 *
 * @param referenceKey  The batch key of the reference batch group.
 * @param targetUuid    UUID of one representative object already in the group
 *                      (excluded from the returned list).
 * @param scene         The THREE.Scene to scan.
 * @param registry      The ComponentRegistry used by isBatchable.
 * @returns             BatchGroupInspectResult with rejected candidates.
 */
export function findSimilarMeshes(
  referenceKey: string,
  targetUuid: string,
  scene: THREE.Object3D,
  registry: ComponentRegistryImpl,
): BatchGroupInspectResult {
  const keyBreakdown = parseBatchKey(referenceKey);
  const referencePrimitive = keyBreakdown.primitive;
  const similarRejected: SimilarMeshResult[] = [];

  scene.traverse((obj) => {
    // Skip the reference object itself.
    if (obj.uuid === targetUuid) return;

    const renderer = getMeshRenderer(obj);
    if (!renderer) return;

    // Only consider objects with the same primitive (same geometry family).
    if (renderer.primitive !== referencePrimitive) return;

    const mesh = getHostMesh(obj);
    if (!mesh) return;

    // Check batchability first.
    const { batchable, reason } = isBatchable(obj, registry);
    if (!batchable) {
      similarRejected.push({
        uuid: obj.uuid,
        name: obj.name,
        reason: reason as ExclusionReason,
      });
      return;
    }

    // Object is batchable but might produce a different key.
    // TRN-350: the composite key used by collectAndBatch appends "|mir" for
    // negative-determinant instances. getBatchKey only returns the base key, so
    // we compute the mirrored flag separately and build the composite candidate key
    // to compare against the reference (which may also include the "|mir" suffix).
    const baseCandidateKey = getBatchKey(
      renderer as Parameters<typeof getBatchKey>[0],
      mesh,
    );
    obj.updateWorldMatrix(true, false);
    const candidateMirrored = obj.matrixWorld.determinant() < 0;
    const candidateKey = candidateMirrored ? `${baseCandidateKey}|mir` : baseCandidateKey;

    if (candidateKey !== referenceKey) {
      // Identify the first differing key field.
      // Strip |mir suffix for the field-level comparison (parseBatchKey handles
      // the base key format; the mir flag is reported separately below).
      const refBaseKey = referenceKey.endsWith('|mir')
        ? referenceKey.slice(0, -4)
        : referenceKey;
      const refMirrored = referenceKey.endsWith('|mir');

      const candidateBreakdown = parseBatchKey(baseCandidateKey);
      const refBreakdown = parseBatchKey(refBaseKey);
      let diffReason = `key:differs:${candidateKey}`;

      if (candidateBreakdown.materialId !== refBreakdown.materialId) {
        diffReason = `material differs (${refBreakdown.materialId} vs ${candidateBreakdown.materialId})`;
      } else if (candidateBreakdown.castShadow !== refBreakdown.castShadow) {
        diffReason = `castShadow: ${refBreakdown.castShadow} vs ${candidateBreakdown.castShadow}`;
      } else if (candidateBreakdown.receiveShadow !== refBreakdown.receiveShadow) {
        diffReason = `receiveShadow: ${refBreakdown.receiveShadow} vs ${candidateBreakdown.receiveShadow}`;
      } else if (candidateBreakdown.layerMask !== refBreakdown.layerMask) {
        diffReason = `layerMask: ${refBreakdown.layerMask} vs ${candidateBreakdown.layerMask}`;
      } else if (candidateBreakdown.frustumCulled !== refBreakdown.frustumCulled) {
        diffReason = `frustumCulled: ${refBreakdown.frustumCulled} vs ${candidateBreakdown.frustumCulled}`;
      } else if (candidateBreakdown.uvScale !== refBreakdown.uvScale) {
        diffReason = `worldSpaceUV scale: ${refBreakdown.uvScale ?? 'none'} vs ${candidateBreakdown.uvScale ?? 'none'}`;
      } else if (candidateMirrored !== refMirrored) {
        // TRN-350: one is a mirrored-transform instance and the other is not.
        diffReason = 'mirroredInstance';
      }

      similarRejected.push({
        uuid: obj.uuid,
        name: obj.name,
        reason: diffReason,
      });
    }
    // If candidateKey === referenceKey this object IS in the same batch — skip it.
  });

  return { referenceKey, keyBreakdown, similarRejected };
}
