/**
 * LODGroupInspector — store-wired wrapper for the LODBarWidget.
 *
 * This component replaces the generic field loop for LODGroup components in the
 * Inspector. It receives `onSetProp` from ComponentCard so it can commit both
 * `levels` and `cullScreenHeight` independently via the undo stack without
 * creating a circular dependency on editor-ui.
 *
 * Registered via PackEditorExtensions.inspectors['LODGroup']. ComponentCard
 * checks getInspector() before falling back to the generic schema field loop.
 *
 * Props: { uuid, component, componentIndex, onSetProp } — onSetProp is passed
 * down by ComponentCard so the inspector can commit individual prop changes
 * without directly importing the editor store.
 */

import type { ComponentJSON } from '@threenity/core';
import { LODBarWidget, type LODLevel, type ChildEntity } from './LODBarWidget.js';

export interface LODGroupInspectorProps {
  uuid: string;
  component: ComponentJSON;
  componentIndex: number;
  /** Provided by ComponentCard — commits a single prop change to the undo stack. */
  onSetProp: (key: string, value: unknown) => void;
  /** TRN-117: direct children of host — populated by ComponentCard via the editor store. */
  hostChildren?: ChildEntity[];
}

export function LODGroupInspector({ component, onSetProp, hostChildren }: LODGroupInspectorProps): JSX.Element {
  const props = component.props ?? {};
  const levels = props['levels'];
  const cullScreenHeight = typeof props['cullScreenHeight'] === 'number'
    ? props['cullScreenHeight']
    : null;

  const handleLevelsChange = (next: LODLevel[]): void => {
    onSetProp('levels', next);
  };

  const handleCullHeightChange = (next: number | null): void => {
    onSetProp('cullScreenHeight', next);
  };

  return (
    <LODBarWidget
      value={levels}
      onChange={handleLevelsChange}
      cullScreenHeight={cullScreenHeight}
      onCommitCullHeight={handleCullHeightChange}
      hostChildren={hostChildren}
    />
  );
}
