/**
 * Scene-report heuristics — editor-only.
 *
 * Each heuristic receives a `SceneReportInput` snapshot and returns zero or more
 * suggestion strings. Having heuristics in their own module keeps them pure (no
 * DOM, no React) and fully unit-testable with synthetic fixtures.
 *
 * Import exclusively from editor code — not from runtime or play paths.
 */

import { parseBatchKey } from '../../batching/whyNotBatched.js';

// ---------------------------------------------------------------------------
// Input types
// ---------------------------------------------------------------------------

/** Minimal material descriptor built by buildSceneReport from live THREE materials. */
export interface MaterialDescriptor {
  /** Asset path / id, or an auto-generated label for inline materials. */
  id: string;
  /** THREE material type name, e.g. "MeshStandardMaterial". */
  shaderType: string;
  /** Hex string, e.g. "#ff0000". */
  color: string;
  metalness: number;
  roughness: number;
  /** Whether the material uses the worldSpaceUV shader injection. */
  worldSpaceUV: boolean;
  /** Whether perInstanceVariant is enabled on this material. */
  perInstanceVariant: boolean;
  /** Whether noBatch is set on the MeshRenderer that uses this material. */
  noBatch: boolean;
  /** Texture map IDs present on the material (albedo, normal, roughness, etc.). */
  maps: string[];
  /**
   * Stable texture identity keys per slot — used to detect when materials
   * share identical textures vs only the presence of a map slot.
   * Format: `{ albedo?: string, normal?: string, ... }` where the value is
   * the texture uuid (stable within a session).
   */
  mapIds: Partial<Record<string, string>>;
  /** Number of meshes referencing this material. */
  meshCount: number;
}

/** Batch group descriptor. */
export interface BatchGroupDescriptor {
  key: string;
  count: number;
  /** Any split reason for groups that did not merge with similar peers. */
  splitReason?: string;
}

export interface SceneReportInput {
  materials: MaterialDescriptor[];
  batchGroups: BatchGroupDescriptor[];
  /** Number of active GPU shader programs (renderer.info.programs.length). */
  programCount: number;
}

// ---------------------------------------------------------------------------
// Individual heuristics — each returns suggestion strings
// ---------------------------------------------------------------------------

/**
 * Compute a canonical map-identity signature for a material: a sorted,
 * joined string of all non-empty texture uuid values present in mapIds.
 * Two materials with identical signatures have the exact same textures.
 */
function mapIdentitySignature(m: MaterialDescriptor): string {
  return Object.entries(m.mapIds)
    .filter(([, v]) => Boolean(v))
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([k, v]) => `${k}:${v}`)
    .join('|');
}

/**
 * Materials that share shader+settings and differ only by their map set could
 * be atlas-baked to collapse them into one batch.
 *
 * When maps are IDENTICAL across the group, the materials should already
 * collapse via per-instance variant batching (TRN-342) — a different
 * suggestion is emitted in that case.
 */
export function hintAtlasCandidates(input: SceneReportInput): string[] {
  const suggestions: string[] = [];
  const mats = input.materials;

  // Group materials by their "structural fingerprint" (everything except maps).
  const groups = new Map<string, MaterialDescriptor[]>();
  for (const m of mats) {
    const key = `${m.shaderType}|${m.color}|${m.metalness.toFixed(3)}|${m.roughness.toFixed(3)}|${m.worldSpaceUV}|${m.perInstanceVariant}`;
    const list = groups.get(key);
    if (list) {
      list.push(m);
    } else {
      groups.set(key, [m]);
    }
  }

  for (const group of groups.values()) {
    // Only flag when >=2 materials share everything except maps AND each has
    // at least one map (plain color materials don't benefit from an atlas).
    const withMaps = group.filter((m) => m.maps.length > 0);
    if (withMaps.length < 2) continue;

    // Deduplicate ids — avoid listing the same asset path 130 times.
    const uniqueIds = [...new Set(withMaps.map((m) => m.id))];
    const label = uniqueIds.join(', ');

    // Determine whether all members share IDENTICAL textures or truly differ.
    const signatures = withMaps.map((m) => mapIdentitySignature(m));
    const allSameTextures = signatures.every((s) => s === signatures[0]);

    if (allSameTextures) {
      // Maps are identical — this should already collapse via PIV (TRN-342).
      // If materials are still separate, it's either a keygen bug or they differ
      // in non-render params (color, etc.) that keygen doesn't see yet.
      suggestions.push(
        `Materials ${label} share identical shader+textures and differ only in non-render params — they should collapse via per-instance variant batching (TRN-342). If they are still split, file a bug.`,
      );
    } else {
      // Maps genuinely differ — atlas baking would collapse them.
      suggestions.push(
        `Materials ${label} share shader+settings and differ only by map — bake an atlas (TRN-344) to collapse them.`,
      );
    }
  }
  return suggestions;
}

/**
 * Materials with perInstanceVariant:false that have the same base key as other
 * groups could opt in and batch together.
 */
export function hintPerInstanceVariant(input: SceneReportInput): string[] {
  const suggestions: string[] = [];
  for (const m of input.materials) {
    if (!m.perInstanceVariant && m.meshCount > 1) {
      // Only suggest when more than one mesh references this material — otherwise
      // opting in would not reduce draw calls.
      suggestions.push(
        `Material "${m.id}" has perInstanceVariant disabled and is used by ${m.meshCount} meshes — enable it to allow per-instance color/UV variation without splitting the batch.`,
      );
    }
  }
  return suggestions;
}

/**
 * Warn about potential shader-program explosion: many distinct shader programs
 * relative to distinct materials usually means shader variant proliferation.
 */
export function hintShaderProgramCount(input: SceneReportInput): string[] {
  const suggestions: string[] = [];
  const { programCount, materials } = input;
  const matCount = materials.length;

  // Flag when programs significantly outnumber unique materials.
  // Heuristic threshold: more than 2× material count, minimum 4 programs.
  if (programCount >= 4 && matCount > 0 && programCount > matCount * 2) {
    const worldUVMats = materials
      .filter((m) => m.worldSpaceUV || m.perInstanceVariant)
      .map((m) => m.id);
    const suspect = worldUVMats.length > 0 ? ` Suspect: ${worldUVMats.join(', ')}.` : '';
    suggestions.push(
      `${programCount} shader programs active for ${matCount} material(s) — possible variant explosion.${suspect}`,
    );
  }
  return suggestions;
}

/**
 * Batch groups that split due to map differences are atlas candidates (more
 * specific than hintAtlasCandidates — targets groups that already tried to merge).
 */
export function hintSplitMapGroups(input: SceneReportInput): string[] {
  const suggestions: string[] = [];
  for (const g of input.batchGroups) {
    if (g.splitReason && g.splitReason.includes('material differs')) {
      const breakdown = parseBatchKey(g.key);
      suggestions.push(
        `Batch "${breakdown.primitive}" split because: ${g.splitReason} — consider atlas baking (TRN-344).`,
      );
    }
  }
  return suggestions;
}

// ---------------------------------------------------------------------------
// Public: run all heuristics
// ---------------------------------------------------------------------------

/** All registered heuristics in priority order. */
const HEURISTICS = [
  hintAtlasCandidates,
  hintSplitMapGroups,
  hintPerInstanceVariant,
  hintShaderProgramCount,
] as const;

/**
 * Run all heuristics against the given input and return a flat list of
 * suggestion strings. Empty array when no issues are detected.
 */
export function runHeuristics(input: SceneReportInput): string[] {
  const suggestions: string[] = [];
  for (const heuristic of HEURISTICS) {
    for (const s of heuristic(input)) {
      suggestions.push(s);
    }
  }
  return suggestions;
}
