/**
 * ProfilerBatchOverlay — click-capture layer for the F3 Profiler HUD (TRN-343).
 *
 * Editor-only. Not exported from pack-core's runtime index.ts.
 *
 * Attaches a sibling transparent overlay div next to the Profiler HUD that
 * captures clicks on batch-group rows without altering the HUD's
 * `pointerEvents: none` rule (Option B per Human decision 2026-05-08).
 *
 * The overlay is positioned to cover only the batch-key rows of the HUD.
 * It updates whenever batching stats change so the clickable regions stay
 * aligned with the displayed rows.
 *
 * Usage (editor-app):
 *   const overlay = mountProfilerBatchOverlay((key) => openBatchInspector(key));
 *   // ... later:
 *   overlay.dispose();
 */

import {
  onBatchingStatsChange,
  getBatchingStats,
  type BatchingStats,
} from '../../batching/batchingManager.js';

// HUD font metrics (must match Profiler.ts #installHud):
//   font: '11px/1.35 ui-monospace, ...'
const HUD_FONT_SIZE_PX = 11;
const HUD_LINE_HEIGHT = 1.35;
const HUD_LINE_PX = HUD_FONT_SIZE_PX * HUD_LINE_HEIGHT; // ~14.85
const HUD_PADDING_TOP_PX = 6;
const HUD_PADDING_HORIZ_PX = 10;

/**
 * Number of fixed text lines that appear before the first batch-key row.
 *
 * Structure from Profiler.ts #updateHud (when batchCount > 0 and showBatchDetail=true):
 *   0: — profiler (hotkey) —
 *   1: fps …
 *   2: dt ms  cur … avg …
 *   3:         min … max …
 *   4: spikes …
 *   5: — gpu —
 *   6: calls …
 *   7: tris …
 *   8: progs …
 *   9: geoms …
 *  10: texs …
 *  11: — scene —
 *  12: objects …
 *  13: — batching —
 *  14: Batches: …
 *  15: <first batch key row>   ← clickable starts here
 */
const FIXED_LINES_BEFORE_BATCH_ROWS = 15;

export interface ProfilerBatchOverlayHandle {
  /** Remove the overlay element and unsubscribe from stats updates. */
  dispose(): void;
}

/**
 * Mount a transparent click-capture overlay over the Profiler HUD batch rows.
 *
 * @param onBatchGroupClick  Called with the raw batch key string when the user
 *                           clicks a batch-group row.
 * @returns  A handle with a `dispose()` method to clean up.
 */
export function mountProfilerBatchOverlay(
  onBatchGroupClick: (key: string) => void,
): ProfilerBatchOverlayHandle {
  const overlay = document.createElement('div');
  overlay.className = 'threenity-profiler-batch-overlay';
  overlay.style.cssText = [
    'position: fixed',
    'pointer-events: none',   // overlay itself non-capturing; only buttons inside capture
    'z-index: 99999',
    'overflow: hidden',
    'background: transparent',
  ].join('; ');

  document.body.appendChild(overlay);

  function syncPosition(stats: BatchingStats): void {
    const hud = document.querySelector<HTMLElement>('.threenity-profiler-hud');
    if (!hud || hud.style.display === 'none') {
      overlay.style.display = 'none';
      return;
    }

    const rect = hud.getBoundingClientRect();
    const rowCount = Math.min(stats.byKey.length, 5);

    if (rowCount === 0) {
      overlay.style.display = 'none';
      return;
    }

    // Top of the first batch row inside the HUD.
    const rowsOffsetTop = HUD_PADDING_TOP_PX + FIXED_LINES_BEFORE_BATCH_ROWS * HUD_LINE_PX;
    const overlayTop = rect.top + rowsOffsetTop;
    const overlayLeft = rect.left;
    const overlayWidth = rect.width;
    const overlayHeight = rowCount * HUD_LINE_PX;

    overlay.style.display = 'block';
    overlay.style.top = `${overlayTop}px`;
    overlay.style.left = `${overlayLeft}px`;
    overlay.style.width = `${overlayWidth}px`;
    overlay.style.height = `${overlayHeight}px`;

    // Rebuild buttons — one per batch row.
    overlay.innerHTML = '';
    stats.byKey.slice(0, 5).forEach((entry, i) => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.style.cssText = [
        'position: absolute',
        `top: ${i * HUD_LINE_PX}px`,
        'left: 0',
        `width: calc(100% - ${HUD_PADDING_HORIZ_PX}px)`,
        `height: ${HUD_LINE_PX}px`,
        'background: transparent',
        'border: none',
        'cursor: pointer',
        'padding: 0',
        'pointer-events: auto',
        'outline: none',
      ].join('; ');
      btn.title = `Open batch inspector: ${entry.key}`;
      btn.setAttribute('aria-label', `Inspect batch group ${entry.key}`);
      btn.addEventListener('click', () => { onBatchGroupClick(entry.key); });
      overlay.appendChild(btn);
    });
  }

  // Subscribe to live stats so overlay updates when batch data changes.
  const unsubscribe = onBatchingStatsChange(syncPosition);

  // Initial sync with whatever stats are already in memory.
  syncPosition(getBatchingStats());

  return {
    dispose(): void {
      unsubscribe();
      overlay.remove();
    },
  };
}
