/**
 * buildSceneReport — assembles the plain-text multi-section scene report.
 *
 * Editor-only. Not imported from runtime or play paths.
 *
 * Combines:
 *  - live THREE.Scene traversal for the Materials section,
 *  - BatchingStats.byKey for the Batches section,
 *  - heuristics.ts for the Suggestions section.
 */

import * as THREE from 'three';
import type { BatchingStats } from '../../batching/batchingManager.js';
import { parseBatchKey } from '../../batching/whyNotBatched.js';
import { getSpatialReport } from '../../spatial/spatialIndex.js';
import {
  runHeuristics,
  type MaterialDescriptor,
  type BatchGroupDescriptor,
  type SceneReportInput,
} from './heuristics.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Return a hex string for a THREE.Color. */
function colorHex(color: THREE.Color): string {
  return `#${color.getHexString()}`;
}

/** Safely read a string property from an object. */
function strProp(obj: Record<string, unknown>, key: string): string {
  const v = obj[key];
  return typeof v === 'string' ? v : '';
}

/** Return a short label for a texture: its name, or its uuid prefix. */
function texLabel(tex: THREE.Texture): string {
  return tex.name || tex.uuid.slice(0, 8);
}

/** Return "[WxH]" size string for a texture image if available. */
function texSize(tex: THREE.Texture): string {
  const img = tex.image as { width?: number; height?: number } | undefined | null;
  if (img && typeof img.width === 'number' && typeof img.height === 'number') {
    return `[${img.width}x${img.height}]`;
  }
  return '';
}

/** Format a texture reference as "name[WxH]" or "(none)". */
function fmtTex(tex: THREE.Texture | null | undefined): string {
  if (!tex) return '(none)';
  const sz = texSize(tex);
  return sz ? `${texLabel(tex)} ${sz}` : texLabel(tex);
}

// ---------------------------------------------------------------------------
// Materials section
// ---------------------------------------------------------------------------

interface MaterialInfo {
  descriptor: MaterialDescriptor;
  /** Raw THREE material for display. */
  mat: THREE.Material;
}

function collectMaterials(scene: THREE.Object3D): MaterialInfo[] {
  // Key: stable asset path (sfMaterialId) when available, else mat.uuid.
  // This prevents the same asset loading as multiple THREE.Material instances
  // from producing 80+ duplicate entries in the report.
  const seen = new Map<string, MaterialInfo>();

  scene.traverse((obj) => {
    // Gather materials from direct Mesh children (non-instanced).
    for (const child of obj.children) {
      if (!(child instanceof THREE.Mesh) || child instanceof THREE.InstancedMesh) continue;
      const mats = Array.isArray(child.material) ? child.material : [child.material];

      // Gather noBatch from sfComponents on the host (parent) object.
      const sfComponents = obj.userData['sfComponents'];
      let noBatch = false;
      if (Array.isArray(sfComponents)) {
        for (const c of sfComponents as unknown[]) {
          if (c !== null && typeof c === 'object' && typeof (c as Record<string, unknown>)['noBatch'] === 'boolean') {
            noBatch = (c as Record<string, unknown>)['noBatch'] as boolean;
            break;
          }
        }
      }

      for (const mat of mats) {
        if (!mat) continue;
        const ud = mat.userData as Record<string, unknown>;

        // Prefer stable asset path over volatile uuid so the same material
        // asset loaded multiple times collapses into one entry.
        // Priority: sfMaterialId (asset path) > mat.name > mat.uuid.
        // mat.name is set by the material loader to the asset path string and
        // is stable across instances; uuid is per-instance and must not be
        // used for dedup when a name is available.
        const assetPath = strProp(ud, 'sfMaterialId');
        const stableKey = assetPath || mat.name || mat.uuid;

        if (seen.has(stableKey)) {
          const existing = seen.get(stableKey)!;
          existing.descriptor.meshCount++;
          // noBatch is a per-host flag — mark true if ANY host using this material has it.
          if (noBatch) existing.descriptor.noBatch = true;
          continue;
        }

        const worldSpaceUV = ud['sfWorldUV'] != null;
        const perInstanceVariant = ud['sfPerInstanceVariant'] === true;

        let color = '#ffffff';
        let metalness = 0;
        let roughness = 1;
        const maps: string[] = [];
        const mapIds: Record<string, string> = {};

        if (mat instanceof THREE.MeshStandardMaterial) {
          color = colorHex(mat.color);
          metalness = mat.metalness;
          roughness = mat.roughness;
          if (mat.map) { maps.push(fmtTex(mat.map)); mapIds['albedo'] = mat.map.uuid; }
          if (mat.normalMap) { maps.push(fmtTex(mat.normalMap)); mapIds['normal'] = mat.normalMap.uuid; }
          if (mat.roughnessMap) { maps.push(fmtTex(mat.roughnessMap)); mapIds['roughness'] = mat.roughnessMap.uuid; }
          if (mat.metalnessMap) { maps.push(fmtTex(mat.metalnessMap)); mapIds['metalness'] = mat.metalnessMap.uuid; }
          if (mat.emissiveMap) { maps.push(fmtTex(mat.emissiveMap)); mapIds['emissive'] = mat.emissiveMap.uuid; }
          if (mat.aoMap) { maps.push(fmtTex(mat.aoMap)); mapIds['ao'] = mat.aoMap.uuid; }
        } else if (mat instanceof THREE.MeshBasicMaterial) {
          color = colorHex(mat.color);
          if (mat.map) { maps.push(fmtTex(mat.map)); mapIds['albedo'] = mat.map.uuid; }
        }

        const matId = assetPath || mat.name || mat.uuid.slice(0, 8);

        seen.set(stableKey, {
          mat,
          descriptor: {
            id: matId,
            shaderType: mat.constructor.name || mat.type,
            color,
            metalness,
            roughness,
            worldSpaceUV,
            perInstanceVariant,
            noBatch,
            maps,
            mapIds,
            meshCount: 1,
          },
        });
      }
    }
  });

  // Sort by meshCount descending so heaviest consumers appear first.
  const infos = Array.from(seen.values());
  infos.sort((a, b) => b.descriptor.meshCount - a.descriptor.meshCount);
  return infos;
}

function renderMaterialsSection(infos: MaterialInfo[]): string[] {
  if (infos.length === 0) return ['  (no materials found)'];
  return infos.map(({ descriptor: d, mat }) => {
    const ud = mat.userData as Record<string, unknown>;
    const lines: string[] = [
      `  [${d.id}]`,
      `    shader: ${d.shaderType}`,
      `    color: ${d.color}  metalness: ${d.metalness.toFixed(2)}  roughness: ${d.roughness.toFixed(2)}`,
    ];

    // Texture maps with sizes.
    if (mat instanceof THREE.MeshStandardMaterial) {
      lines.push(`    albedo:    ${fmtTex(mat.map)}`);
      lines.push(`    normal:    ${fmtTex(mat.normalMap)}`);
      lines.push(`    roughness: ${fmtTex(mat.roughnessMap)}`);
      lines.push(`    metalness: ${fmtTex(mat.metalnessMap)}`);
      lines.push(`    emissive:  ${fmtTex(mat.emissiveMap)}`);
      lines.push(`    ao:        ${fmtTex(mat.aoMap)}`);
    } else if (mat instanceof THREE.MeshBasicMaterial) {
      lines.push(`    albedo: ${fmtTex(mat.map)}`);
    }

    lines.push(`    worldSpaceUV: ${d.worldSpaceUV}  perInstanceVariant: ${d.perInstanceVariant}  noBatch: ${d.noBatch}`);
    lines.push(`    meshCount: ${d.meshCount}`);

    // sfMaterialId asset path if present.
    const assetPath = strProp(ud, 'sfMaterialId');
    if (assetPath) lines.push(`    assetPath: ${assetPath}`);

    return lines.join('\n');
  });
}

// ---------------------------------------------------------------------------
// Batches section
// ---------------------------------------------------------------------------

function renderBatchesSection(
  stats: BatchingStats,
): { lines: string[]; descriptors: BatchGroupDescriptor[] } {
  if (stats.byKey.length === 0) {
    return {
      lines: ['  (no active batches — run collectAndBatch first)'],
      descriptors: [],
    };
  }

  const descriptors: BatchGroupDescriptor[] = [];
  const lines: string[] = [];

  // Summary
  lines.push(
    `  Total batches: ${stats.batchCount}  |  Instanced: ${stats.batchedInstances}  |  Saved: ${stats.savedDrawCalls} draw calls`,
  );

  // Per-group detail.
  for (const entry of stats.byKey) {
    const bd = parseBatchKey(entry.key);
    const saved = entry.count - 1;
    const flags: string[] = [];
    if (bd.uvScale) flags.push(`worldSpaceUV:${bd.uvScale}`);

    const parts = [
      `  [${bd.primitive}] mat:${bd.materialId} ×${entry.count} (saved ${saved} calls)`,
      `    key: ${entry.key}`,
      `    castShadow:${bd.castShadow} receiveShadow:${bd.receiveShadow} frustumCulled:${bd.frustumCulled} layerMask:${bd.layerMask}`,
    ];
    if (flags.length) parts.push(`    flags: ${flags.join(' ')}`);

    descriptors.push({ key: entry.key, count: entry.count });
    lines.push(parts.join('\n'));
  }

  // Exclusion reason summary (if any).
  const reasons = Object.entries(stats.exclusionReasons);
  if (reasons.length) {
    lines.push('  Exclusions:');
    for (const [reason, count] of reasons.sort((a, z) => z[1] - a[1])) {
      lines.push(`    ${reason}: ${count}`);
    }
  }

  // tooSmallGroups.
  if (stats.tooSmallGroups.length) {
    lines.push('  Groups below minInstancesPerBatch:');
    for (const g of stats.tooSmallGroups) {
      const bd = parseBatchKey(g.key);
      lines.push(`    ${bd.primitive}|${bd.materialId}: ${g.count} instance(s)`);
    }
  }

  return { lines, descriptors };
}

// ---------------------------------------------------------------------------
// Not-static breakdown section
// ---------------------------------------------------------------------------

/** Maximum example object names listed per group before the "… and N more" truncation. */
const MAX_EXAMPLES_PER_GROUP = 5;

/**
 * Render the "=== Not-static breakdown ===" section from the not-static exclusion
 * records captured during collectAndBatch (TRN-348 Session 5).
 *
 * Grouping: by (geometryName, materialId) pair.
 * Output per group:  "  Cube + materials/Home/WallHome ×61"
 * Followed by up to 5 example names (with uuid) and optionally their prefab root.
 * Groups are sorted by count descending.
 */
function renderNotStaticBreakdown(stats: BatchingStats): string[] {
  const records = stats.notStaticObjects;
  if (!records || records.length === 0) return ['  (none)'];

  // Group by (geometryName|materialId).
  const groupMap = new Map<string, typeof records>();
  for (const rec of records) {
    const key = `${rec.geometryName}\x00${rec.materialId}`;
    let g = groupMap.get(key);
    if (!g) {
      g = [];
      groupMap.set(key, g);
    }
    g.push(rec);
  }

  // Sort groups by count descending.
  const sorted = [...groupMap.entries()].sort((a, z) => z[1].length - a[1].length);

  const lines: string[] = [];
  for (const [key, members] of sorted) {
    const sep = key.indexOf('\x00');
    const geoName = key.slice(0, sep);
    const matId = key.slice(sep + 1);
    lines.push(`  ${geoName} + ${matId} \xD7${members.length}`);

    const examples = members.slice(0, MAX_EXAMPLES_PER_GROUP);
    for (const ex of examples) {
      const prefabSuffix = ex.prefabRootPath ? ` [prefab: ${ex.prefabRootPath}]` : '';
      lines.push(`    • ${ex.name} (${ex.uuid.slice(0, 8)})${prefabSuffix}`);
    }
    const remaining = members.length - examples.length;
    if (remaining > 0) {
      lines.push(`    … and ${remaining} more`);
    }
  }
  return lines;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export interface SceneReportOptions {
  scene: THREE.Object3D;
  stats: BatchingStats;
  /** renderer.info.programs.length — may be 0 if unavailable. */
  programCount: number;
}

/**
 * Build the full plain-text scene report as a single string.
 *
 * The report has three sections:
 *   === Materials ===
 *   === Batches ===
 *   === Suggestions ===
 *
 * Calling this is synchronous; all data is read from the live scene + stats
 * snapshot at call time.
 */
export function buildSceneReport(opts: SceneReportOptions): string {
  const { scene, stats, programCount } = opts;

  const materialInfos = collectMaterials(scene);
  const materialDescriptors = materialInfos.map((i) => i.descriptor);

  const { lines: batchLines, descriptors: batchDescriptors } = renderBatchesSection(stats);

  const heuristicsInput: SceneReportInput = {
    materials: materialDescriptors,
    batchGroups: batchDescriptors,
    programCount,
  };
  const suggestions = runHeuristics(heuristicsInput);

  const sections: string[] = [];

  sections.push('=== Materials ===');
  sections.push(renderMaterialsSection(materialInfos).join('\n\n'));

  sections.push('=== Batches ===');
  sections.push(batchLines.join('\n\n'));

  sections.push('=== Suggestions ===');
  if (suggestions.length === 0) {
    sections.push('  No suggestions — scene looks well-optimized.');
  } else {
    sections.push(suggestions.map((s, i) => `  ${i + 1}. ${s}`).join('\n'));
  }

  // Only emit the breakdown when there are actually not-static exclusions.
  const notStaticCount = stats.exclusionReasons['not-static'] ?? 0;
  if (notStaticCount > 0) {
    sections.push('=== Not-static breakdown ===');
    sections.push(renderNotStaticBreakdown(stats).join('\n'));
  }

  sections.push('=== Spatial index (TRN-345) ===');
  sections.push(getSpatialReport());

  return sections.join('\n\n');
}
