/**
 * LODBarWidget — Unity-style LOD inspector widget for LODGroup component.
 *
 * Renders a horizontal bar split into coloured segments per LOD level.
 * Bar goes from screenHeight=1.0 (left/high-quality) to 0.0 (right/low-detail).
 * If cullScreenHeight is set, a red Culled segment occupies the right edge.
 *
 * Uses native HTML elements and inline styles (no radix-ui / lucide deps)
 * so this file can typecheck cleanly inside pack-core.
 *
 * Features (TRN-109 + TRN-114):
 *  - Drag handles between segments change screenHeight boundaries.
 *  - Right-most boundary drag controls cullScreenHeight.
 *  - Live camera-position marker above the bar using editor camera rAF loop.
 *  - Keyboard: segments are focusable buttons; Enter selects; arrows move selection.
 *  - Fade Mode dropdown: visual stub only (no schema field).
 *  - Culled segment is selectable; shows Cull Height (%) input + Remove Culled button.
 *  - LOD 0 Remove button is disabled (cannot remove first level).
 *  - Add Culled button when cull=null.
 *  - Add-after inserts midpoint between current level and next lower border (cull or 0).
 *  - Cull Height displayed in percent (0–100); runtime value stays fraction (0..1).
 *  - Per-level body shows targets[] (child UUID list) as a read-only placeholder.
 *    TODO(TRN-117): replace with interactive child-picker once editor-ui exposes
 *    a getChildrenOf(hostUuid) store helper.
 *
 * Registered via PackEditorExtensions.inspectors['LODGroup'] through LODGroupInspector.
 * Pure math and logic are in ../lodMath.ts.
 */

import { useState, useEffect, useRef, useCallback, type CSSProperties } from 'react';
import {
  computeRelativeHeight,
  clampBoundaryScreenHeight,
  computeCullHeightFromDrag,
  addLevelAfter as mathAddLevelAfter,
  parsePercentInput,
  type SphereData,
  type CameraData,
} from '../lodMath.js';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface LODLevel {
  screenHeight: number;
  /** Child UUIDs managed at this LOD level (TRN-113 shape). */
  targets?: string[];
  /** Legacy asset ref — accepted during normalisation, ignored in UI (TRN-109 compat). */
  asset?: string;
}

export interface ChildEntity {
  uuid: string;
  name: string;
}

export interface LODBarWidgetProps {
  value: unknown;
  onChange: (next: LODLevel[]) => void;
  cullScreenHeight?: number | null;
  onCommitCullHeight?: (next: number | null) => void;
  /** TRN-117: direct children of host, used for the per-level multi-select picker. */
  hostChildren?: ChildEntity[];
}

// Re-export for test imports.
export { computeRelativeHeight };

/** Sentinel index meaning the Culled segment is selected (not a real level). */
const CULLED_SELECTED = -1;

// ---------------------------------------------------------------------------
// Colour palette
// ---------------------------------------------------------------------------

function segmentColour(index: number): string {
  return `hsl(${(index * 67) % 360}, 50%, 35%)`;
}

const CULLED_BG = 'hsl(0, 35%, 22%)';
const CULLED_BG_SELECTED = 'hsl(0, 45%, 30%)';

// ---------------------------------------------------------------------------
// Normalise value
// ---------------------------------------------------------------------------

function normaliseLevels(raw: unknown): LODLevel[] {
  if (!Array.isArray(raw)) return [];
  return (raw as unknown[]).map((item) => {
    if (item && typeof item === 'object') {
      const rec = item as Record<string, unknown>;
      const targets = Array.isArray(rec['targets'])
        ? (rec['targets'] as unknown[]).filter((t): t is string => typeof t === 'string')
        : [];
      return {
        screenHeight: typeof rec['screenHeight'] === 'number' ? rec['screenHeight'] : 0.5,
        targets,
      };
    }
    return { screenHeight: 0.5, targets: [] };
  });
}

// ---------------------------------------------------------------------------
// Segment layout
// ---------------------------------------------------------------------------

interface SegmentLayout {
  left: number;
  width: number;
}

function computeSegments(
  levels: LODLevel[],
  cullH: number | null,
): { segments: SegmentLayout[]; culledSegment: SegmentLayout | null } {
  const sorted = [...levels].sort((a, b) => b.screenHeight - a.screenHeight);
  const rightEdge = cullH ?? 0;

  const segments: SegmentLayout[] = sorted.map((lvl, i) => {
    const rightBound = i + 1 < sorted.length
      ? sorted[i + 1]!.screenHeight
      : rightEdge;
    const segLeft = 1 - lvl.screenHeight;
    const segRight = 1 - rightBound;
    return { left: segLeft, width: segRight - segLeft };
  });

  const culledSegment =
    (cullH !== null && cullH > 0)
      ? { left: 1 - cullH, width: cullH }
      : null;

  return { segments, culledSegment };
}

