// ---------------------------------------------------------------------------
// Main widget
// ---------------------------------------------------------------------------

export function LODBarWidget({ value, onChange, cullScreenHeight, onCommitCullHeight, hostChildren }: LODBarWidgetProps): JSX.Element {
  const levels = normaliseLevels(value);
  const sorted = [...levels].sort((a, b) => b.screenHeight - a.screenHeight);

  // selectedIndex: 0..sorted.length-1 for LOD levels, CULLED_SELECTED (-1) for Culled segment.
  const [selectedIndex, setSelectedIndex] = useState<number>(0);
  const [markerPos, setMarkerPos] = useState<number | null>(null);
  // Controlled input state for cull height field (in percent string form).
  const [cullInputValue, setCullInputValue] = useState<string>('');
  const barRef = useRef<HTMLDivElement>(null);
  const cullInputRef = useRef<HTMLInputElement>(null);

  const cullH = cullScreenHeight ?? null;

  // Keep the cull input in sync when the prop changes (e.g. from drag).
  // Only update if not currently focused to avoid fighting the user.
  useEffect(() => {
    if (cullInputRef.current === document.activeElement) return;
    setCullInputValue(cullH !== null ? String(Math.round(cullH * 100)) : '');
  }, [cullH]);

  // Stable refs so the boundary-drag closure can read the latest levels and
  // sort order without re-creating listeners on every commit (which previously
  // dropped pointer capture and froze the cursor).
  const levelsRef = useRef<LODLevel[]>(levels);
  const sortedRef = useRef<LODLevel[]>(sorted);
  levelsRef.current = levels;
  sortedRef.current = sorted;

  const { segments, culledSegment } = computeSegments(sorted, cullH);

  // ---- Live marker: rAF loop ------------------------------------------------

  useEffect(() => {
    let rafId: number;

    function tick(): void {
      rafId = requestAnimationFrame(tick);
      const cam = (globalThis as Record<string, unknown>)['__threenityEditorCamera'] as CameraData | undefined;
      const sphere = (globalThis as Record<string, unknown>)['__threenitySelectedEntitySphere'] as SphereData | undefined;
      if (
        cam && sphere &&
        typeof cam.fov === 'number' &&
        typeof cam.getWorldPosition === 'function' &&
        typeof sphere.radius === 'number'
      ) {
        const relH = computeRelativeHeight(sphere, cam);
        setMarkerPos(1 - relH);
      } else {
        setMarkerPos(null);
      }
    }

    rafId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafId);
  }, []);

  // ---- Boundary drag --------------------------------------------------------

  const handleBoundaryDrag = useCallback(
    (boundaryIndex: number, e: React.PointerEvent<HTMLDivElement>) => {
      e.preventDefault();
      e.stopPropagation();

      const bar = barRef.current;
      if (!bar) return;

      const isCullBoundary = boundaryIndex === sortedRef.current.length;

      let sourceIndex = -1;
      if (!isCullBoundary) {
        const origLevel = sortedRef.current[boundaryIndex];
        if (!origLevel) return;
        sourceIndex = levelsRef.current.findIndex(
          (l) => l.screenHeight === origLevel.screenHeight,
        );
        if (sourceIndex === -1) return;
      }

      const onMove = (moveE: PointerEvent): void => {
        const rect = bar.getBoundingClientRect();
        const fraction = (moveE.clientX - rect.left) / rect.width;
        const newScreenHeight = Math.max(0, Math.min(1, 1 - fraction));

        if (isCullBoundary) {
          if (onCommitCullHeight) {
            onCommitCullHeight(computeCullHeightFromDrag(fraction));
          }
          return;
        }

        const latestLevels = levelsRef.current;
        const latestSorted = sortedRef.current;
        const clamped = clampBoundaryScreenHeight(newScreenHeight, latestSorted, boundaryIndex);
        const nextLevels = latestLevels.map((l, i) =>
          i === sourceIndex ? { ...l, screenHeight: clamped } : l,
        );
        onChange([...nextLevels].sort((a, b) => b.screenHeight - a.screenHeight));
      };

      const onEnd = (): void => {
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onEnd);
        window.removeEventListener('pointercancel', onEnd);
        window.removeEventListener('blur', onEnd);
      };

      // Use window-level listeners (no setPointerCapture) so re-renders during
      // the drag don't strip the capture target. Symmetric cleanup on up/cancel/blur
      // guarantees we never leave the cursor stuck.
      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onEnd);
      window.addEventListener('pointercancel', onEnd);
      window.addEventListener('blur', onEnd);
    },
    [onChange, onCommitCullHeight],
  );

  // ---- Level body actions ---------------------------------------------------

  const handleAddAfter = (idx: number): void => {
    const asSorted = sorted.map((l) => ({ screenHeight: l.screenHeight, asset: '' }));
    const updated = mathAddLevelAfter(asSorted, idx, cullH);
    if (updated === asSorted) return; // no room
    // Merge back with original targets data: new levels have targets:[]; existing levels keep theirs.
    const newLevels: LODLevel[] = updated.map((u) => {
      const orig = sorted.find((s) => s.screenHeight === u.screenHeight);
      return orig ?? { screenHeight: u.screenHeight, targets: [] };
    });
    onChange(newLevels);
    setSelectedIndex(Math.min(idx + 1, newLevels.length - 1));
  };

  const handleRemove = (idx: number): void => {
    if (idx === 0) return; // LOD 0 is locked
    if (sorted.length <= 1) return;
    const lvl = sorted[idx];
    if (!lvl) return;
    const updated = levels
      .filter((l) => l.screenHeight !== lvl.screenHeight)
      .sort((a, b) => b.screenHeight - a.screenHeight);
    onChange(updated);
    setSelectedIndex(Math.max(0, idx - 1));
  };

  const handleRemoveCulled = (): void => {
    if (onCommitCullHeight) {
      onCommitCullHeight(null);
      setSelectedIndex(0);
    }
  };

  const handleAddCulled = (): void => {
    if (onCommitCullHeight) {
      const lastLevel = sorted[sorted.length - 1];
      const lastSH = lastLevel ? lastLevel.screenHeight : 0.1;
      const midpoint = lastSH / 2;
      onCommitCullHeight(midpoint > 0.001 ? midpoint : 0.05);
    }
  };

  // TRN-117: toggle a child UUID in the selected level's targets[].
  const handleToggleTarget = (idx: number, childUuid: string): void => {
    const lvl = sorted[idx];
    if (!lvl) return;
    const current = lvl.targets ?? [];
    const next = current.includes(childUuid)
      ? current.filter((u) => u !== childUuid)
      : [...current, childUuid];
    onChange(
      levels
        .map((l) =>
          l.screenHeight === lvl.screenHeight
            ? { ...l, targets: next }
            : l,
        )
        .sort((a, b) => b.screenHeight - a.screenHeight),
    );
  };

  const handleScreenHeightChange = (idx: number, newVal: number): void => {
    const lvl = sorted[idx];
    if (!lvl) return;
    const clamped = clampBoundaryScreenHeight(newVal, sorted, idx);
    onChange(
      levels
        .map((l) =>
          l.screenHeight === lvl.screenHeight
            ? { ...l, screenHeight: clamped }
            : l,
        )
        .sort((a, b) => b.screenHeight - a.screenHeight),
    );
  };

  // ---- Keyboard nav ---------------------------------------------------------

  const handleKeyDown = (e: React.KeyboardEvent, idx: number): void => {
    if (e.key === 'Enter') { setSelectedIndex(idx); e.preventDefault(); }
    if (e.key === 'ArrowLeft' && idx > 0) { setSelectedIndex(idx - 1); e.preventDefault(); }
    if (e.key === 'ArrowRight' && idx < sorted.length - 1) { setSelectedIndex(idx + 1); e.preventDefault(); }
  };

  // Clamp selectedIndex in case levels changed.
  const sel = selectedIndex === CULLED_SELECTED ? CULLED_SELECTED
    : Math.min(Math.max(0, selectedIndex), sorted.length - 1);

  const selectedLevel = sel !== CULLED_SELECTED ? sorted[sel] : null;
  const isCulledSelected = sel === CULLED_SELECTED;

  // ---- Add-after disabled check -----------------------------------------------

  function isAddAfterDisabled(idx: number): boolean {
    const lvl = sorted[idx];
    if (!lvl) return true;
    const nextLevelSH = idx + 1 < sorted.length ? sorted[idx + 1]!.screenHeight : null;
    const nextBorder = nextLevelSH !== null ? nextLevelSH : (cullH ?? 0);
    return nextBorder >= lvl.screenHeight;
  }

  // ---- Cull input handlers ---------------------------------------------------

  const handleCullInputChange = (raw: string): void => {
    setCullInputValue(raw);
    if (raw.trim() === '') return;
    const fraction = parsePercentInput(raw);
    if (fraction !== null && onCommitCullHeight) {
      onCommitCullHeight(fraction);
    }
  };

  const handleCullInputBlur = (): void => {
    if (cullInputValue.trim() === '' && onCommitCullHeight) {
      onCommitCullHeight(null);
    }
    setCullInputValue(cullH !== null ? String(Math.round(cullH * 100)) : '');
  };

  // Clamp marker to bar edges so icon stays visible.
  const clampedMarkerPos = markerPos !== null ? Math.max(0, Math.min(1, markerPos)) : null;

  return (
    <div style={S['widget']}>
      {/* Fade Mode stub */}
      <div style={S['fadeModeRow']}>
        <span style={S['fadeModeLabel']}>Fade Mode</span>
        <select style={S['fadeModeSelect']} disabled>
          <option value="None">None</option>
        </select>
      </div>

      {/* LOD bar */}
      <div style={S['barWrapper']}>
        {clampedMarkerPos !== null && (
          <div style={{ ...S['markerContainer'], left: `${clampedMarkerPos * 100}%` }}>
            {/* Camera icon — Unity-LOD-style, tinted accent */}
            <svg width="20" height="16" viewBox="0 0 24 24" fill="var(--sf-accent, #5588cc)" stroke="var(--sf-accent, #5588cc)" strokeWidth="1.5" strokeLinejoin="round">
              <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z" />
              <circle cx="12" cy="13" r="4" fill="#0d1117" />
            </svg>
            <span style={S['markerLabel']}>{Math.round((1 - clampedMarkerPos) * 100)}%</span>
          </div>
        )}

        <div ref={barRef} style={S['bar']} role="group" aria-label="LOD levels">
          {sorted.map((lvl, i) => {
            const seg = segments[i];
            if (!seg) return null;
            const isSelected = sel === i;
            const bg = isSelected
              ? `hsl(${(i * 67) % 360}, 55%, 45%)`
              : segmentColour(i);
            const outline = isSelected
              ? '2px solid var(--sf-accent, #5588cc)'
              : undefined;
            return (
              <button
                key={`${lvl.screenHeight}-${i}`}
                type="button"
                style={{
                  ...S['segment'],
                  left: `${seg.left * 100}%`,
                  width: `${seg.width * 100}%`,
                  background: bg,
                  outline,
                  outlineOffset: outline ? -2 : undefined,
                }}
                aria-pressed={isSelected}
                aria-label={`LOD ${i}`}
                onClick={() => setSelectedIndex(i)}
                onKeyDown={(e) => handleKeyDown(e, i)}
              >
                <span style={S['segmentLabel']}>LOD {i}</span>
                <span style={S['segmentPct']}>{Math.round(lvl.screenHeight * 100)}%</span>
              </button>
            );
          })}

          {culledSegment && (
            <button
              type="button"
              style={{
                ...S['culledSegment'],
                left: `${culledSegment.left * 100}%`,
                width: `${culledSegment.width * 100}%`,
                background: isCulledSelected ? CULLED_BG_SELECTED : CULLED_BG,
                outline: isCulledSelected ? '2px solid var(--sf-accent, #5588cc)' : undefined,
                outlineOffset: isCulledSelected ? -2 : undefined,
              }}
              aria-pressed={isCulledSelected}
              aria-label="Culled"
              onClick={() => setSelectedIndex(CULLED_SELECTED)}
            >
              <span style={S['segmentLabel']}>Culled</span>
              <span style={S['segmentPct']}>{Math.round((cullH ?? 0) * 100)}%</span>
            </button>
          )}

          {/* Drag handles between segments */}
          {sorted.map((_, i) => {
            if (i === 0) return null;
            const seg = segments[i];
            if (!seg) return null;
            return (
              <div
                key={`handle-${i}`}
                style={{ ...S['handle'], left: `${seg.left * 100}%` }}
                onPointerDown={(e) => handleBoundaryDrag(i, e)}
                title="Drag to adjust boundary"
                role="separator"
                aria-orientation="vertical"
              >
                <div style={S['handleInner']} />
              </div>
            );
          })}

          {/* Right-most handle: controls cullScreenHeight */}
          {onCommitCullHeight && (() => {
            const lastSeg = segments[segments.length - 1];
            if (!lastSeg) return null;
            const handleLeft = lastSeg.left + lastSeg.width;
            if (handleLeft >= 0.999) return null;
            return (
              <div
                key="handle-cull"
                style={{ ...S['handle'], left: `${handleLeft * 100}%` }}
                onPointerDown={(e) => handleBoundaryDrag(sorted.length, e)}
                title="Drag to set cull threshold"
                role="separator"
                aria-orientation="vertical"
              >
                <div style={S['handleInner']} />
              </div>
            );
          })()}
        </div>
      </div>

      {/* Add Culled button — only shown when cull is null */}
      {onCommitCullHeight && cullH === null && (
        <div style={S['addCulledRow']}>
          <button
            type="button"
            style={S['addBtn']}
            onClick={handleAddCulled}
            title="Add Culled zone"
          >
            + Add Culled
          </button>
        </div>
      )}

      {/* Selected LOD level body */}
      {!isCulledSelected && selectedLevel && (
        <div style={S['levelBody']}>
          <div style={S['levelRow']}>
            <span style={S['levelLabel']}>Screen Height</span>
            <div style={S['levelControl']}>
              <input
                type="number"
                style={S['levelInput']}
                value={selectedLevel.screenHeight.toFixed(3)}
                min={0}
                max={1}
                step={0.01}
                onChange={(e) => {
                  const v = parseFloat(e.target.value);
                  if (!isNaN(v)) handleScreenHeightChange(sel as number, v);
                }}
              />
              <input
                type="range"
                style={S['levelSlider']}
                min={0}
                max={1}
                step={0.001}
                value={selectedLevel.screenHeight}
                onChange={(e) => handleScreenHeightChange(sel as number, parseFloat(e.target.value))}
              />
            </div>
          </div>

          <div style={{ ...S['levelRow'], alignItems: 'flex-start' }}>
            <span style={{ ...S['levelLabel'], paddingTop: 4 }}>Targets</span>
            <div style={S['levelControl']}>
              {/* TRN-117: interactive child-picker. */}
              {hostChildren && hostChildren.length > 0 ? (
                <div style={S['targetsPicker']}>
                  {(() => {
                    const explicit = new Set(selectedLevel.targets ?? []);
                    // TRN-118: if this level's targets is empty, the runtime resolves
                    // it to "all unclaimed direct children of host". Surface that in UI
                    // by marking unclaimed children as effectively-included (italic).
                    const claimedByOthers = new Set<string>();
                    for (const lvl of sorted) {
                      if (lvl.screenHeight === selectedLevel.screenHeight) continue;
                      for (const u of lvl.targets ?? []) claimedByOthers.add(u);
                    }
                    const isImplicitMode = explicit.size === 0;
                    return hostChildren.map((c) => {
                      const isExplicit = explicit.has(c.uuid);
                      const isUnclaimedAndImplicit =
                        isImplicitMode && !claimedByOthers.has(c.uuid);
                      const checked = isExplicit || isUnclaimedAndImplicit;
                      return (
                        <label
                          key={c.uuid}
                          style={{
                            ...S['targetsRow'],
                            ...(isExplicit ? S['targetsRowChecked'] : {}),
                            ...(isUnclaimedAndImplicit && !isExplicit ? S['targetsRowUnclaimed'] : {}),
                          }}
                        >
                          <input
                            type="checkbox"
                            style={S['targetsCheckbox']}
                            checked={checked}
                            onChange={() => handleToggleTarget(sel as number, c.uuid)}
                          />
                          <span style={S['targetsName']}>{c.name || '(unnamed)'}</span>
                          {isUnclaimedAndImplicit && !isExplicit && (
                            <span style={S['targetsBadge']} title="Implicitly included because targets[] is empty (all unclaimed)">auto</span>
                          )}
                        </label>
                      );
                    });
                  })()}
                </div>
              ) : (
                <div style={S['targetsEmpty']}>No direct children — parent meshes under this object first.</div>
              )}
            </div>
          </div>

          <div style={S['levelActions']}>
            {/* Remove is disabled for LOD 0 (index 0 in sorted desc array) */}
            <button
              type="button"
              style={sel === 0 ? S['removeBtnDisabled'] : S['removeBtn']}
              onClick={() => handleRemove(sel as number)}
              disabled={sel === 0}
              aria-disabled={sel === 0}
              title={sel === 0 ? 'LOD 0 cannot be removed' : 'Remove this level'}
            >
              − Remove
            </button>
            {(() => {
              const addDisabled = isAddAfterDisabled(sel as number);
              return (
                <button
                  type="button"
                  style={addDisabled ? S['addBtnDisabled'] : S['addBtn']}
                  onClick={() => !addDisabled && handleAddAfter(sel as number)}
                  disabled={addDisabled}
                  aria-disabled={addDisabled}
                  title={addDisabled ? 'No room — adjust LOD 0 first' : 'Add level after this one'}
                >
                  + Add after
                </button>
              );
            })()}
          </div>
        </div>
      )}

      {/* Selected Culled segment body */}
      {isCulledSelected && cullH !== null && onCommitCullHeight && (
        <div style={S['levelBody']}>
          <div style={S['levelRow']}>
            <span style={S['levelLabel']}>Cull Height (%)</span>
            <div style={S['levelControl']}>
              <input
                ref={cullInputRef}
                type="number"
                style={S['cullInput']}
                value={cullInputValue}
                placeholder="e.g. 5"
                min={0}
                max={100}
                step={1}
                onChange={(e) => handleCullInputChange(e.target.value)}
                onBlur={handleCullInputBlur}
              />
            </div>
          </div>
          <div style={S['levelActions']}>
            <button
              type="button"
              style={S['removeBtn']}
              onClick={handleRemoveCulled}
              title="Remove Culled zone (sets cullScreenHeight to null)"
            >
              − Remove Culled
            </button>
          </div>
        </div>
      )}

      {/* Bottom cull height row (shown only when a normal level is selected, and cull is set) */}
      {!isCulledSelected && onCommitCullHeight && cullH !== null && (
        <div style={S['cullRow']}>
          <span style={S['cullLabel']}>Cull Height (%)</span>
          <input
            type="number"
            style={S['cullInput']}
            value={cullInputValue}
            placeholder="e.g. 5"
            min={0}
            max={100}
            step={1}
            onChange={(e) => handleCullInputChange(e.target.value)}
            onBlur={handleCullInputBlur}
          />
        </div>
      )}
    </div>
  );
}
