/**
 * Pure math/logic helpers for the LOD inspector widget.
 *
 * Extracted from LODBarWidget.tsx so they can be imported and tested
 * without requiring React/JSX.
 */

const DEG2RAD = Math.PI / 180;

export interface SphereData {
  center: { x: number; y: number; z: number };
  radius: number;
}

/**
 * Camera shape we accept: just enough surface to extract a world-space position.
 * Compatible with THREE.PerspectiveCamera (which mutates the Vector3 target via
 * setFromMatrixPosition), and with plain test stubs that read camera.position
 * directly without going through getWorldPosition.
 */
export interface CameraData {
  fov: number;
  /** Optional: present on real THREE cameras; absent on minimal test stubs. */
  matrixWorld?: { elements: ArrayLike<number> };
  /** Optional: minimal stubs may expose plain camera.position instead of matrixWorld. */
  position?: { x: number; y: number; z: number };
  /**
   * Optional THREE-compatible accessor. Real cameras call
   * `target.setFromMatrixPosition(this.matrixWorld)`, so the target must
   * have that method (i.e. be a real Vector3). We don't rely on this anymore
   * because we read matrixWorld directly — but the field stays in the type
   * so existing code that passes a real camera still typechecks.
   */
  getWorldPosition?: (out: unknown) => unknown;
}

function _readCameraWorldPos(camera: CameraData): { x: number; y: number; z: number } | null {
  // Prefer matrixWorld (THREE cameras): position is the translation column (12,13,14).
  const m = camera.matrixWorld?.elements;
  if (m && m.length >= 16) {
    return { x: m[12] as number, y: m[13] as number, z: m[14] as number };
  }
  // Test-stub form: getWorldPosition mutates a plain {x,y,z} target.
  if (typeof camera.getWorldPosition === 'function') {
    try {
      const target = { x: 0, y: 0, z: 0 } as { x: number; y: number; z: number };
      const result = camera.getWorldPosition(target) as { x?: unknown; y?: unknown; z?: unknown } | undefined;
      const r = result ?? target;
      if (typeof r.x === 'number' && typeof r.y === 'number' && typeof r.z === 'number') {
        return { x: r.x, y: r.y, z: r.z };
      }
    } catch {
      // fall through
    }
  }
  if (camera.position) {
    return { x: camera.position.x, y: camera.position.y, z: camera.position.z };
  }
  return null;
}

/**
 * Compute the object's relative screen height given its bounding sphere and
 * a perspective camera. Mirrors LODGroup.ts #selectLevel formula:
 *
 *   relH = min(1, (2*radius) / (distance * 2 * tan(fov/2)))
 *
 * Returns 0 for degenerate inputs (zero radius, camera inside sphere, no pos).
 */
export function computeRelativeHeight(sphere: SphereData, camera: CameraData): number {
  const camPos = _readCameraWorldPos(camera);
  if (!camPos) return 0;
  const dx = sphere.center.x - camPos.x;
  const dy = sphere.center.y - camPos.y;
  const dz = sphere.center.z - camPos.z;
  const distance = Math.sqrt(dx * dx + dy * dy + dz * dz);
  if (distance <= 0 || sphere.radius <= 0) return 0;
  const halfFovRad = (camera.fov * 0.5) * DEG2RAD;
  return Math.min(1, (2 * sphere.radius) / (distance * 2 * Math.tan(halfFovRad)));
}

export interface LODLevelData {
  screenHeight: number;
  /** Legacy asset field — optional after TRN-113 schema change (targets replaces asset). */
  asset?: string;
}

/**
 * Clamp a new screenHeight for boundary at `boundaryIndex` between its
 * neighbours so it never crosses adjacent levels.
 */
export function clampBoundaryScreenHeight(
  newVal: number,
  sorted: LODLevelData[],
  boundaryIndex: number,
): number {
  const lower = boundaryIndex + 1 < sorted.length
    ? sorted[boundaryIndex + 1]!.screenHeight + 0.001
    : 0.001;
  const upper = boundaryIndex > 0
    ? sorted[boundaryIndex - 1]!.screenHeight - 0.001
    : 0.999;
  return Math.max(lower, Math.min(upper, newVal));
}

/**
 * Compute the new cullScreenHeight from a right-most boundary drag.
 * `rawFraction` is 0..1 where 0=left(screenHeight=1) and 1=right(screenHeight=0).
 * Returns null when dragged back to the right edge (screenHeight <= 0.001).
 */
export function computeCullHeightFromDrag(rawFraction: number): number | null {
  const newScreenHeight = Math.max(0, Math.min(1, 1 - rawFraction));
  return newScreenHeight <= 0.001 ? null : newScreenHeight;
}

/**
 * Apply a model asset drop to the level at `targetIndex` (in sorted order).
 * Returns a new levels array with the asset updated on the matching level.
 */
export function applyAssetDrop(
  levels: LODLevelData[],
  targetIndex: number,
  assetId: string,
): LODLevelData[] {
  const sorted = [...levels].sort((a, b) => b.screenHeight - a.screenHeight);
  const level = sorted[targetIndex];
  if (!level) return levels;
  return levels.map((l) =>
    l.screenHeight === level.screenHeight ? { ...l, asset: assetId } : l,
  );
}

/**
 * Add a new level after `insertAfterIndex` (in sorted order).
 *
 * The new level's screenHeight is the midpoint between the current level and
 * the next lower border. The next lower border is (in priority order):
 *   1. The next level's screenHeight (if one exists)
 *   2. `cullScreenHeight` (if non-null)
 *   3. 0
 *
 * Returns the new array sorted desc by screenHeight. Returns the original
 * array unchanged if there is no room (nextBorder >= currentScreenHeight).
 */
export function addLevelAfter(
  levels: LODLevelData[],
  insertAfterIndex: number,
  cullScreenHeight?: number | null,
): LODLevelData[] {
  const sorted = [...levels].sort((a, b) => b.screenHeight - a.screenHeight);
  const lvl = sorted[insertAfterIndex];
  if (!lvl) return levels;

  const nextLevelSH = insertAfterIndex + 1 < sorted.length
    ? sorted[insertAfterIndex + 1]!.screenHeight
    : null;

  const nextBorder = nextLevelSH !== null
    ? nextLevelSH
    : (cullScreenHeight != null ? cullScreenHeight : 0);

  // No room — caller should disable the button in this case.
  if (nextBorder >= lvl.screenHeight) return levels;

  const newScreenHeight = (lvl.screenHeight + nextBorder) / 2;
  const newLevel: LODLevelData = {
    screenHeight: Math.max(0.001, newScreenHeight),
    asset: '',
  };
  return [...levels, newLevel].sort((a, b) => b.screenHeight - a.screenHeight);
}

/**
 * Parse a percent/fraction input string to a fraction value (0..1).
 *
 * Strategy: always-percent input is the primary UX. We accept:
 *   "5"    → 0.05  (treated as percent; the range is 0..100)
 *   "5%"   → 0.05
 *   "0.05" → 0.05  (any value ≤ 1.0 with a decimal point is treated as fraction)
 *
 * Disambiguation rule:
 *   If the raw numeric value is > 1 → percent (divide by 100).
 *   If the raw numeric value is ≤ 1 AND the original string contains a '.' → fraction.
 *   If the raw numeric value is ≤ 1 AND no '.' → percent (e.g. "0" → 0%, "1" → 1%).
 *
 * Returns null for unparseable input.
 */
export function parsePercentInput(raw: string): number | null {
  const trimmed = raw.trim().replace(/%$/, '');
  const n = parseFloat(trimmed);
  if (isNaN(n)) return null;
  let fraction: number;
  if (n > 1) {
    fraction = n / 100;
  } else if (trimmed.includes('.')) {
    // explicit fraction like "0.05"
    fraction = n;
  } else {
    // integer ≤ 1 with no decimal — treat as percent (0 → 0%, 1 → 1%)
    fraction = n / 100;
  }
  return Math.max(0, Math.min(1, fraction));
}
