/**
 * BatchingControllerInspector — bulk Static mark/unmark accordion.
 *
 * Bulk marking is scoped, not blanket: the primary paths are by Hierarchy roots
 * (mark a parent's subtree) or by tag. "Mark all" exists but is gated behind a
 * confirmation prompt because it indiscriminately stamps every eligible object.
 *
 * Each action produces ONE undoable JSON-Patch command covering all mutations.
 * No import from @threenity/editor-ui — respects pack ↔ editor-ui boundary.
 */

import { useState, useMemo } from 'react';
import type { DragEvent } from 'react';
import type { ComponentJSON, ObjectJSON, SceneJSON, Command } from '@threenity/core';
import { createCommand } from '@threenity/core';
import { isEligibleForStaticMark } from '../../batching/eligibilityCheck.js';

// Mirror of HIERARCHY_OBJECT_MIME defined in editor-ui's hierarchy/dragdrop.ts.
// Inlined here because pack-core must not import from @threenity/editor-ui.
const HIERARCHY_OBJECT_MIME = 'application/x-threenity-object-uuid';

export interface BatchingControllerInspectorProps {
  uuid: string;
  component: ComponentJSON;
  componentIndex: number;
  onSetProp: (key: string, value: unknown) => void;
  scene: SceneJSON;
  selection: string[];
  executeCommand: (cmd: Command) => void;
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function bulkStaticCommand(
  scene: SceneJSON,
  targets: ObjectJSON[],
  value: boolean,
  label: string,
): Command | null {
  type ReplaceOp = { op: 'replace'; path: string; value: boolean };
  const doOps: ReplaceOp[] = [];
  const undoOps: ReplaceOp[] = [];

  for (const obj of targets) {
    const idx = scene.objects.findIndex((o) => o.uuid === obj.uuid);
    if (idx < 0) continue;
    const prev = scene.objects[idx]!.static ?? false;
    if (prev === value) continue;
    const path = `/objects/${idx}/static`;
    doOps.push({ op: 'replace', path, value });
    undoOps.unshift({ op: 'replace', path, value: prev });
  }

  if (doOps.length === 0) return null;
  return createCommand({ label, do: doOps, undo: undoOps });
}

/** Collect selection + all descendants (by parent uuid) from the scene graph. */
function collectSubtree(scene: SceneJSON, rootUuids: string[]): ObjectJSON[] {
  if (rootUuids.length === 0) return [];
  const childrenByParent = new Map<string, ObjectJSON[]>();
  for (const obj of scene.objects) {
    const p = obj.parent;
    if (p == null) continue;
    const arr = childrenByParent.get(p);
    if (arr) arr.push(obj);
    else childrenByParent.set(p, [obj]);
  }
  const visited = new Set<string>();
  const out: ObjectJSON[] = [];
  const stack = [...rootUuids];
  while (stack.length > 0) {
    const id = stack.pop()!;
    if (visited.has(id)) continue;
    visited.add(id);
    const obj = scene.objects.find((o) => o.uuid === id);
    if (!obj) continue;
    out.push(obj);
    const kids = childrenByParent.get(id);
    if (kids) for (const k of kids) stack.push(k.uuid);
  }
  return out;
}

/** Parse comma/space-separated tag input into a unique trimmed list. */
function parseTags(input: string): string[] {
  return Array.from(
    new Set(
      input
        .split(/[,\s]+/)
        .map((t) => t.trim())
        .filter((t) => t.length > 0),
    ),
  );
}

