/**
 * Editor-side eligibility check for static batching (TRN-146).
 *
 * Mirrors the runtime rules in criteria.ts rules 4–6, but operates on
 * `ObjectJSON` (scene JSON) instead of `THREE.Object3D`. Used exclusively
 * by the BatchingControllerInspector to determine which objects can receive
 * `static: true` without hitting a genuine-conflict exclusion.
 *
 * Rules mirrored (criteria.ts rule numbers shown):
 *  4. dynamic RigidBody (sfRigidBody with type === 'dynamic' — stored in userData
 *     at runtime, but in scene JSON it's a component prop on a RigidBody component
 *     with `type === 'dynamic'`).
 *  5. Animator component present anywhere in the host's component list.
 *  6. SkinnedMeshRenderer or ModelRenderer component present on the object.
 *
 * Rules NOT checked here (irrelevant at scene-JSON level):
 *  0. Static gate — this function is called to decide whether to SET static.
 *  1. MeshRenderer.noBatch — the prop exists in scene JSON but is a runtime
 *     authoring choice; "Mark all eligible" intentionally respects it by
 *     excluding those objects (see below in hasMeshRendererNoBatch).
 *  2. sfBatchExclude / sfVfxOwned / sfLodOwned — these are runtime userData
 *     stamps, not scene JSON fields. Cannot be checked editor-side; accepted risk.
 *  3. movesTransform — registry-driven, not available in scene JSON. Skipped.
 *  7. layer mask — scene JSON stores `object.layer` (string name), not a
 *     THREE.Layers bitmask. Skipped.
 *
 * IMPORTANT: This list MUST stay in sync with criteria.ts. If criteria.ts adds
 * a new "never skipped" rule (like 4, 5, 6), add a parallel check here.
 * Verified by tests/batchingControllerInspector.test.ts parity assertions.
 */

import type { ObjectJSON, ComponentJSON } from '@threenity/core';

/** Component type names that permanently disqualify an object from batching. */
const BLOCKING_COMPONENT_TYPES = new Set([
  'Animator',
  'SkinnedMeshRenderer',
  'ModelRenderer',
]);

/** Reason codes for static-batching ineligibility (TRN-142). */
export type StaticBlockReason =
  | 'animator'
  | 'skinnedMesh'
  | 'modelRenderer'
  | 'dynamicRigidBody'
  | 'noBatch';

/** Structured result returned by {@link checkStaticEligibility}. */
export interface StaticEligibilityResult {
  eligible: boolean;
  blockedBy?: StaticBlockReason;
}

/**
 * Returns a structured eligibility result for static batching.
 *
 * Same rules as {@link isEligibleForStaticMark} but also names which rule
 * first blocks the object. Used by the Inspector Header warning icon (TRN-142).
 */
export function checkStaticEligibility(object: ObjectJSON): StaticEligibilityResult {
  const comps: ComponentJSON[] = object.components ?? [];

  for (const comp of comps) {
    if (comp.type === 'Animator') return { eligible: false, blockedBy: 'animator' };
    if (comp.type === 'SkinnedMeshRenderer') return { eligible: false, blockedBy: 'skinnedMesh' };
    if (comp.type === 'ModelRenderer') return { eligible: false, blockedBy: 'modelRenderer' };

    if (
      (comp.type === 'RigidBody' || comp.type === 'PhysicsBody') &&
      (comp.props as Record<string, unknown> | undefined)?.['type'] === 'dynamic'
    ) {
      return { eligible: false, blockedBy: 'dynamicRigidBody' };
    }

    if (
      comp.type === 'MeshRenderer' &&
      (comp.props as Record<string, unknown> | undefined)?.['noBatch'] === true
    ) {
      return { eligible: false, blockedBy: 'noBatch' };
    }
  }

  return { eligible: true };
}

/**
 * Returns `true` when the object is eligible to be marked Static for batching.
 *
 * "Eligible" means: stamping `static: true` on this object will not be
 * immediately invalidated by a never-skipped criteria.ts rule.
 *
 * Does NOT check `object.static` — caller decides whether to skip already-static
 * objects (idempotency) or include them (unmark-all).
 */
export function isEligibleForStaticMark(object: ObjectJSON): boolean {
  return checkStaticEligibility(object).eligible;
}
