/**
 * SceneReportWidget — "Dump scene report" button for the F3 Profiler HUD (TRN-348).
 *
 * Editor-only. Not exported from pack-core's runtime index.ts.
 *
 * Injected into the SAME document as the Profiler HUD (the play iframe's
 * document, or the editor document if the runtime is running there). Because
 * it runs in the same browsing context as the HUD,
 * `document.querySelector('.threenity-profiler-hud')` is always able to find
 * the element — solving the parent-doc/iframe boundary problem that made the
 * original SceneReportHost.tsx approach fail (TRN-348 Session 2).
 *
 * The button calls console.log() on click. When running inside the play
 * iframe the parentLogBridge (packages/runtime/src/parentLogBridge.ts) has
 * already replaced console.log, so the output is automatically forwarded to
 * the editor's Console panel via postMessage — no separate bridge needed.
 *
 * Usage (called from inside the iframe runtime — e.g. Profiler.ts):
 *   import { mountSceneReportWidget } from '@threenity/pack-core/editor';
 *   const handle = mountSceneReportWidget(scene, renderer);
 *   // ... later:
 *   handle.dispose();
 */

import type * as THREE from 'three';
import { getBatchingStats } from '../../batching/batchingManager.js';
import { buildSceneReport } from '../sceneReport/buildSceneReport.js';

const BUTTON_OFFSET_PX = 4; // gap between HUD bottom and button top

export interface SceneReportWidgetHandle {
  /** Remove the button element and stop the poll interval. */
  dispose(): void;
}

/**
 * Mount a "Dump scene report" button below the Profiler HUD in the current
 * document (same context as the HUD).
 *
 * @param scene    The live THREE.Object3D tree to traverse for materials.
 * @param renderer Optional THREE.WebGLRenderer — used to read program count.
 *                 Pass null/undefined if unavailable; heuristics degrade gracefully.
 */
export function mountSceneReportWidget(
  scene: THREE.Object3D,
  renderer?: { info?: { programs?: unknown[] } } | null,
): SceneReportWidgetHandle {
  const btn = document.createElement('button');
  btn.type = 'button';
  btn.textContent = 'Dump scene report';
  btn.className = 'threenity-scene-report-btn';
  btn.style.cssText = [
    'position: fixed',
    'display: none',
    'z-index: 99999',
    'padding: 3px 6px',
    'background: rgba(0,0,0,0.72)',
    'color: #b9f5c3',
    'font: 10px/1.4 ui-monospace, Menlo, Consolas, monospace',
    'border: 1px solid rgba(185,245,195,0.4)',
    'border-radius: 0 0 4px 4px',
    'cursor: pointer',
    'text-align: left',
    'pointer-events: auto',
    'white-space: nowrap',
    'overflow: hidden',
    'text-overflow: ellipsis',
  ].join('; ');

  btn.title = 'Dump full scene materials + batches + suggestions to the engine Console';

  btn.addEventListener('click', () => {
    const stats = getBatchingStats();
    const programCount = (renderer?.info?.programs as unknown[] | undefined)?.length ?? 0;
    const report = buildSceneReport({ scene, stats, programCount });
    // eslint-disable-next-line no-console
    console.log('[SceneReport]\n' + report);
  });

  document.body.appendChild(btn);

  function syncPosition(): void {
    const hud = document.querySelector<HTMLElement>('.threenity-profiler-hud');
    if (!hud || hud.style.display === 'none') {
      btn.style.display = 'none';
      return;
    }
    const rect = hud.getBoundingClientRect();
    btn.style.display = 'block';
    btn.style.top = `${rect.bottom + BUTTON_OFFSET_PX}px`;
    btn.style.left = `${rect.left}px`;
    btn.style.width = `${rect.width}px`;
  }

  syncPosition();
  const intervalId = window.setInterval(syncPosition, 500);

  return {
    dispose(): void {
      window.clearInterval(intervalId);
      btn.remove();
    },
  };
}
